var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"블레이드! 카타스트로피!!","JPN":"ブレイド！　カタストロフィ！！","ENG":"Blade! Catastrophe!","TWN":"刀刃！災禍！！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"......해치웠나?","JPN":"やったか……？","ENG":"Did we win?","TWN":"……解決了嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"후, 후훗...... 역시 내 실력은 모자란 게 아니었어.","JPN":"フ、フフ……やっぱり私の実力が足りないわけじゃなかった。","ENG":"Hah, hah hah... So I had it in me after all.","TWN":"嘻嘻……果然不是我實力不足。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"내가 마음만 먹으면 편입생 같은 <color=#ffd34c>프로</color>가 되는 것도 금방이라고!","JPN":"やろうと思えば編入生と同じ<color=#ffd34c>プロ</color>になるのもすぐよ！","ENG":"I'll become a <color=#ffd34c>pro</color> like the transfer student in no time, as long as I'm up for it!","TWN":"只要我下定決心，成為插班生那樣的<color=#ffd34c>專業制裁者</color>也是輕而易舉的！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하나 충고드리면 프로는 <color=#ffd34c>해치웠나</color> 같은 말은 쓰면 안 되는 법이랍니다.","JPN":"一つアドバイスするとしたら、プロは<color=#ffd34c>やったか？</color>みたいな言葉は安易に使いませんね。","ENG":"Pro tip. Real pros don't say stuff like <color=#ffd34c>\\"Did we win?\\"</color>","TWN":"給你一個忠告，專業制裁者可不會說<color=#ffd34c>解決了嗎</color>這種話。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"기본은 나쁘지 않은데 마무리가 살짝 어설프시네요.","JPN":"基本は悪くありませんが、詰めが甘いです。","ENG":"You got the basics right, but your finishing moves could use more work.","TWN":"你的基礎雖然不錯，但收尾有些粗糙。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_EXPLOSION_FIRE_BIG"},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그런데 방금 말한 편입생이 누군지 물어 봐도 될까요?","JPN":"ところで、さっき言った編入生が誰のことなのか聞いてもいいですか？","ENG":"By the way, may I ask who this transfer student you were talking about is?","TWN":"另外，我能問剛才你提到的插班生是誰嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"제, 제법인데?","JPN":"や、やるじゃない。","ENG":"Th-that was pretty good!","TWN":"有、有兩下子？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"뭐야. 미래의 프로인 나만큼은 아니어도 꽤 소질이 있잖아.","JPN":"将来のプロである私ほどではないけど、かなり素質があるね。","ENG":"Hey, you've got talent, although not as much as my pro future self.","TWN":"你雖然不如我這個未來的專業制裁者，但也很有潛力。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"네가 부탁한다면 내 <color=#ffd34c>아이언 스틸</color>에 들어오게 해 줄 수도 있는데, 어때?","JPN":"望むならうちの<color=#ffd34c>アイアンスチール</color>に入れてやってもいいけど、どう？","ENG":"If you ask nicely, I might even let you join my <color=#ffd34c>Iron Steel</color> team. What do you say?","TWN":"你要是拜託我的話，我讓你進入我的<color=#ffd34c>鋼鐵</color>小隊，怎麼樣？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 말씀은 감사하지만 사양하겠습니다. 이미 괜찮은 회사에 소속되어 있어서요.","JPN":"ハハハ、ありがたいお言葉ですが遠慮しますね。すでにいい会社に所属しているもので。","ENG":"Hah hah, I appreciate the generous offer, but I must decline. I'm already working for a decent company, you see.","TWN":"哈哈，雖然很感謝你的提議，但是我拒絕。因為我已經身在一個很不錯的公司了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"...최면이 너무 강하게 걸렸나?","JPN":"……催眠が強すぎたのかな？","ENG":"Did my hypnosis work a little too well?","TWN":"……催眠效果太強了嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"미카, 여기 있었군요.","JPN":"ミカさん、ここにいたのですね。","ENG":"There you are, Mika.","TWN":"米卡，原來你在這裡。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L29_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"학생회장님!","JPN":"生徒会長！","ENG":"Student President!","TWN":"學生會長！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"구해 주러 오신 거죠! 정말 죽는 줄 알았어요!","JPN":"助けに来てくれたんですね！　本当に危ないところでした！","ENG":"You came to save us! I thought I was going to die for sure!","TWN":"你是來救我們的嗎？我以為死定了呢！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"네, 여기 코핀 컴퍼니 분들이 지원해 주셔서 여유를 낼 수 있었어요.","JPN":"はい、こちらのコフィンカンパニーの方のおかげで来れました。","ENG":"Yes. I managed to find the time to get here thanks to the support of these folks from the Coffin Company.","TWN":"嗯。多虧了這些科芬公司的人支援，我才能來。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"미카도 크게 다친 곳은 없어 보이네요. 다행이에요.","JPN":"ミカさんも大きい怪我はなさそうでよかったです。","ENG":"You seem relatively unscathed, Mika. Thank goodness.","TWN":"米卡看起來也沒有受傷，真是萬幸。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"......그리고 나이엘.","JPN":"……そしてナイエルさん。","ENG":"And as for you, Naielle...","TWN":"……還有奈爾。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"라...... 란체스터 학생회장......님?!","JPN":"ラ……ランチェスター生徒会長……？","ENG":"Ms... Ms. Lanchester?","TWN":"蘭……蘭賈斯特學生會長？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"저는 학생회장으로서, 당신의 지나친 경쟁심과 실력지상주의도 개성의 하나로 여겼습니다.","JPN":"私は生徒会長として、あなたの過度な競争心や実力至上主義も、個性の一つと思いました。","ENG":"As Student President, I excused your excessively competitive nature as a potentially positive personality trait.","TWN":"我作為學生會長，認為你強烈的競爭意識和實力至上主義都只是你個性的一部分。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"나쁜 소문이 돌더라도 가급적 당신이 스스로 깨우쳐 성장하기를 기다렸죠.","JPN":"悪い噂はあったものの、できるだけあなたが自ら悟って成長するのを待っていました。","ENG":"Despite all the bad rumors about you, I thought you deserved the benefit of the doubt until you learned to rectify your own faults.","TWN":"雖然有不好的傳聞，但我一直等待你能自己醒悟和成長。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"하지만...... 존중이란 어디까지나 타인에게 해를 끼치지 않고 조화를 이룰 때 받을 수 있는 겁니다.","JPN":"しかし……尊重とは、他人に危害を加えることなく、調和を成す時に受けることができるものです。","ENG":"However... You can only earn true respect when you make harmony with others, instead of hurting them.","TWN":"可是……受人尊重的前提是不讓其他人遭受傷害且還能夠包容他人。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이번 일은 돌아가는 대로 엄중히 다룰 테니, 각오해 두시길.","JPN":"今回のことはアカデミーに帰還後、厳重に事情聴取しますので覚悟しておいたほうがいいでしょう。","ENG":"You'll have to answer for your actions today once we get back. So brace yourself.","TWN":"這次的事情在回去之後會嚴格的處理，你最好做好心理準備。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"큭......!","JPN":"クッ……！","ENG":"Ugh...","TWN":"唔……！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"나도 알아...... 무슨 벌이든 피하지 않을 테니까 맘대로 해.","JPN":"私もわかってるよ……どんな罰でも受けるから好きにして。","ENG":"I know what I've done. I'm ready to face the consequences... so do what you must.","TWN":"我明白……不管是任何懲罰我都不會逃避，我都會接受。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"좋아요. 그런데 다른 학생들은 어디 있죠?","JPN":"いいでしょう。ところで、他の生徒が見えませんが。","ENG":"Good. Where are the other students, by the way?","TWN":"好，那其他學生都在哪裡？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아 참! 먼저 말씀드렸어야 하는데!","JPN":"そうだ！　先に言うべきでした！","ENG":"Oh, right! I should have told you about that first!","TWN":"哦，對了。忘了告訴你！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"미나는 갑자기 등장한 그림자 침식체와 싸우고 있어요!","JPN":"ミナちゃんは急に出てきたシャドウの侵食体と戦っているんです！","ENG":"Mina is fighting a Shadow-type C.O. that popped out of nowhere!","TWN":"米娜正在跟突然出現的暗影侵蝕體戰鬥！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"잔뜩 긴장해서는 자기가 시간을 벌 테니 우린 먼저 도망치라고......","JPN":"すごく緊張した様子で、時間を稼ぐから先に逃げて、と……","ENG":"She was all tensed up and told us to run while she distracted it...","TWN":"當時氣氛很緊張，她說自己會拖延時間，讓我們先逃……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"미나 학생이...... 그림자와 말인가요?","JPN":"ミナさんが……シャドウをですか？","ENG":"Mina... is fighting a Shadow?","TWN":"米娜同學……和暗影嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"네. 무지 위험한 적 같았어요. 미나 말로는 4종 침식체 수준이라고 했으니까요.","JPN":"はい、超危険な敵らしくて。ミナちゃんの話だと、第4種侵食体並みらしいです。","ENG":"Yes. It looked really dangerous. Mina said it's got to be on par with a Category 4.","TWN":"是的，看起來是個非常危險的敵人。據米娜的話說，大概是4類侵蝕體的水準。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"4종...... 미나 양이 정말 그렇게 말했나요?","JPN":"第4種……本当にミナさんがそう言ったのですか？","ENG":"Category 4... Did she really say that?","TWN":"4類……米娜真的那麼說嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"호오......","JPN":"ほう……","ENG":"Hmm...","TWN":"哇啊……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"4종 침식체라면 아카데미만으로 해결할 수준이 아니군요. 바로 관리국에 알려야겠어요.","JPN":"第4種侵食体ならアカデミーだけで解決できるレベルじゃないですね。すぐ管理局にお知らせします。","ENG":"It will take more than the Academy to handle a Category 4. I must notify the Administration at once.","TWN":"如果是4類侵蝕體水準的話，就沒辦法靠學院處理了。得儘快通知管理局。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L5_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"하지만 4종 침식체라니...... 우연이라기엔 뭔가 석연치 않군요.","JPN":"それにしても第4種侵食体とは……偶然というには少し怪しいですね。","ENG":"But why a Category 4 now? It feels all too suspicious to be a coincidence.","TWN":"但4類侵蝕體……若說是偶然我覺得不太合理。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 본의 아니게 얘기를 들었는데 일이 재밌게 흘러가는 것 같네요.","JPN":"ハハ、不本意ながら話を聞いてしまいましたが、面白い流れになってきたようですね。","ENG":"Hah hah, I didn't mean to eavesdrop, but it sounds like things are getting interesting.","TWN":"哈哈，我雖然不是故意偷聽，但還是覺得事情很有意思。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"현직 종사자로서 어떻게 생각하시나요? 4종 침식체가 이렇게 나타난 사례는 흔치 않을 텐데요?","JPN":"現役カウンターとしてどう思いますか？　第4種侵食体がこのタイミングで現れた事例は滅多にないと思いますが。","ENG":"What's your opinion as a business professional? It's not common for Category 4 C.O.s to appear like this, is it?","TWN":"作為現役制裁者的你怎麼看？畢竟4類侵蝕體並不常見吧？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그렇기야 합니다만, 말씀드린 대로 이면세계란 원래 아무것도 확신할 수 없는 곳이라서요.","JPN":"おっしゃるとおりですが、裏世界とは元々何も問題がないと確信できない場所ですから。","ENG":"Indeed, but like I said, the Counterside is always full of surprises.","TWN":"話雖如此，但這裡畢竟是在異界，誰都無法保證。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"방금 전까지 아무것도 없던 폐허에서 그림자들이 스멀스멀 기어 나올 수도 있는 법이죠.","JPN":"さっきまで何もなかった廃墟からシャドウたちが急に現れることもあり得るでしょう。","ENG":"Even if there's not a single C.O. in sight, Shadows can suddenly start crawling out of nowhere.","TWN":"即使剛剛什麼都沒有的廢墟裡也可能會爬出暗影侵蝕體。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그런데도 학생들을 데리고 훈련을 시키겠다는 발상이라니......","JPN":"そんな所に学生を連れてきて訓練させるなんて……","ENG":"And yet the Academy insists on bringing its students here to train them...","TWN":"竟然帶學生們來這裡進行訓練，這種想法……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이거 참, 처음 듣고 저도 감탄했다니까요.","JPN":"最初に話を聞いた時は、すごい発想だなと驚きましたよ。","ENG":"I was deeply impressed when I first heard about this.","TWN":"我第一次聽到的時候也很吃驚。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"계획을 입안한 사람이 누구인지 꼭 한번 만나보고 싶을 정도로요.","JPN":"計画を立案した人が誰なのか、ぜひ一度会ってみたいと思うほどでした。","ENG":"So much so that I wanted to meet whoever planned this whole idea.","TWN":"計畫這次訓練的人究竟是誰，我真想見一見。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그래요. 저 역시 교직원 측의 통보를 받고 같은 심정이었습니다.","JPN":"そうですね。私も教員側の通達を受けた際は同じ心情でした。","ENG":"I understand. I too felt quite puzzled by the faculty's decision.","TWN":"是啊，我當時接到老師的通知後也是同樣的心情。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"차선책으로 급히 자율 방어 시스템을 투입했지만...... 결국 이렇게 되었군요.","JPN":"次善の策として急遽、自律防御システムを導入しましたが……結局こうなってしまいましたね。","ENG":"Although we deployed the Autonomous Defense System as a backup plan... it ended up like this.","TWN":"作為備用方案，雖然緊急投入了自主防禦系統……但最終事情還是變成了這樣。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"공과는 이 일이 끝난 다음에 가리기로 하죠. 지금은 미나 학생에게 가야 해요.","JPN":"責任追及はこの事態が収束してからにしましょう。今はミナさんのところに急がねば。","ENG":"But we can save the finger-pointing for later. For now, finding Mina is paramount.","TWN":"功過等到事情結束之後再分辨吧。現在當務之急是去米娜同學那裡。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"미카는 먼저 다른 학생들을 복귀시키세요. 저는 이 분들과 함께 미나 학생에게 가겠습니다.","JPN":"ミカさんは先に他の生徒たちと帰還してください。私はこの方たちと一緒にミナさんのところに向かいます。","ENG":"Mika, please go ahead and return with the other students. I will join with this group and find Mina.","TWN":"米卡先跟其他學生們一起回去吧。我會跟這些人一起找米娜同學。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"네, 알겠습니다!","JPN":"はい、わかりました！","ENG":"Understood!","TWN":"是，我知道了！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"어? 왜 그러세요, 회장님?","JPN":"うん？　どうしましたか、会長？","ENG":"Huh? What's wrong, Ms. President?","TWN":"咦？你怎麼了？會長？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"지금 확인해 보니 레이 학생이 없군요. 혹시 미나 학생과 함께 남았나요?","JPN":"今みたらレイさんがいません。もしかして、ミナさんと一緒に残ったのですか？","ENG":"I just noticed that Ray isn't here. Did he stay behind with Mina by any chance?","TWN":"我才發現雷伊同學不在。他是跟米娜同學一起留下了嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"네? 레이 선배는 방금 전까지 우리랑 같이 있었는데요?","JPN":"え？　レイ先輩はさっきまで私たちと一緒にいましたよ？","ENG":"Huh? But Ray was with us just now!","TWN":"啊？雷伊前輩剛剛還在這裡呀？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"정말 안보이네? 어디로 갔지......?","JPN":"本当だ、いない！　どこに消えたの……？","ENG":"I really don't see him! Where did he go?","TWN":"真的不見了？去哪裡了呢？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};